/*
 * Slice 7.6b — embed the cpio-newc initramfs blob into
 * kernel-test.bin's .rodata, flanked by the weak symbols
 * `__ramfs_initramfs_blob_{start,end}` that ramfs's init() looks
 * up.  Production `kernel.bin` doesn't link this file, so the
 * weak fallbacks in ramfs.c stay null and the slurp is skipped.
 *
 * The cpio is generated by `tools/pack-initramfs.py` from a manifest
 * defined in the top-level Makefile (init_prog.elf at /init,
 * hello.txt at /hello in the v1 test build).
 */

.section .rodata
.balign 16
.global __ramfs_initramfs_blob_start
.global __ramfs_initramfs_blob_end

__ramfs_initramfs_blob_start:
.incbin "test/kernel/initramfs.cpio"
__ramfs_initramfs_blob_end:
